# Build the final data structure
citations = []

def add_aya(span, sura_name, sura_number, aya_number, corrected_text):
    citations.append({
        "span_start": span["span_start"],
        "span_end": span["span_end"],
        "span_text": span["span_text"],
        "citation_type": "Aya",
        "is_valid": True,
        "aya_reference": {
            "sura_name": sura_name,
            "sura_number": sura_number,
            "aya_number": aya_number
        },
        "hadeeth_reference": {},
        "corrected_text": corrected_text,
        "completely_invalid": False
    })

def add_hadith(span, collection_name=None, book_number=None, hadith_number=None, corrected_text=None):
    ref = {}
    if collection_name:
        ref["collection_name"] = collection_name
    if book_number is not None:
        ref["book_number"] = book_number
    if hadith_number is not None:
        ref["hadith_number"] = hadith_number
    citations.append({
        "span_start": span["span_start"],
        "span_end": span["span_end"],
        "span_text": span["span_text"],
        "citation_type": "Hadeeth",
        "is_valid": True,
        "aya_reference": {},
        "hadeeth_reference": ref,
        "corrected_text": corrected_text if corrected_text is not None else span["span_text"],
        "completely_invalid": False
    })

